     1→import { useRef, useEffect } from "react";
     2→import { inView, animate } from "motion";
     3→import { Briefcase, Heart, GraduationCap, ArrowRight } from "lucide-react";
     4→
     5→interface AnimatedCardProps {
     6→  title: string;
     7→  description: string;
     8→  href: string;
     9→  icon: string;
    10→  delay?: number;
    11→}
    12→
    13→const iconComponents: Record<string, React.ComponentType<{ className?: string }>> = {
    14→  Briefcase,
    15→  Heart,
    16→  GraduationCap,
    17→};
    18→
    19→export default function AnimatedCard({
    20→  title,
    21→  description,
    22→  href,
    23→  icon,
    24→  delay = 0,
    25→}: AnimatedCardProps) {
    26→  const cardRef = useRef<HTMLAnchorElement>(null);
    27→  const IconComponent = iconComponents[icon] || Briefcase;
    28→
    29→  useEffect(() => {
    30→    const card = cardRef.current;
    31→    if (!card) return;
    32→
    33→    // Check for reduced motion preference
    34→    const prefersReducedMotion = window.matchMedia(
    35→      "(prefers-reduced-motion: reduce)"
    36→    ).matches;
    37→
    38→    if (prefersReducedMotion) {
    39→      card.style.opacity = "1";
    40→      return;
    41→    }
    42→
    43→    // Set initial state
    44→    card.style.opacity = "0";
    45→    card.style.transform = "translateY(30px)";
    46→
    47→    const cleanup = inView(
    48→      card,
    49→      () => {
    50→        animate(
    51→          card,
    52→          { opacity: [0, 1], y: [30, 0] },
    53→          {
    54→            duration: 0.5,
    55→            easing: [0.4, 0, 0.2, 1],
    56→            delay,
    57→          }
    58→        );
    59→      },
    60→      { amount: 0.2 }
    61→    );
    62→
    63→    return cleanup;
    64→  }, [delay]);
    65→
    66→  return (
    67→    <a
    68→      ref={cardRef}
    69→      href={href}
    70→      className="group block bg-white rounded-2xl p-6 md:p-8 shadow-sm border border-neutral-100 hover:shadow-lg hover:border-sakura-200 transition-all duration-300 hover:-translate-y-1"
    71→    >
    72→      {/* Icon */}
    73→      <div className="w-14 h-14 rounded-xl bg-sakura-50 flex items-center justify-center mb-6 group-hover:bg-sakura-100 transition-colors">
    74→        <IconComponent className="w-7 h-7 text-sakura-600" />
    75→      </div>
    76→
    77→      {/* Content */}
    78→      <h3 className="text-xl font-bold text-neutral-900 mb-3 group-hover:text-sakura-600 transition-colors">
    79→        {title}
    80→      </h3>
    81→      <p className="text-neutral-600 text-sm leading-relaxed mb-4">
    82→        {description}
    83→      </p>
    84→
    85→      {/* Link */}
    86→      <div className="flex items-center text-sakura-600 font-medium text-sm">
    87→        <span>詳しく見る</span>
    88→        <ArrowRight className="w-4 h-4 ml-1 group-hover:translate-x-1 transition-transform" />
    89→      </div>
    90→    </a>
    91→  );
    92→}
