    29→
    30→        {/* Content */}
    31→        <div class:list={[
    32→          "ml-12 md:ml-0 md:w-1/2",
    33→          index % 2 === 0 ? "md:pr-12 md:text-right" : "md:pl-12",
    34→        ]}>
    35→          <span class="inline-block px-3 py-1 bg-sakura-100 text-sakura-700 text-sm font-medium rounded-full mb-2">
    36→            {event.year}
